const repos = $input.first().json.repos ?? [];
const since = new Date(Date.now() - 150000).toISOString();
return repos
  .filter(r => r.platform === 'bitbucket' && r.remote_id && r.remote_id.includes('/'))
  .map(r => {
    const [workspace, repo] = r.remote_id.split('/');
    return { json: { workspace, repo, name: r.name, since } };
  });

// Collect PR data with repo context for activity lookup.
const prItems = [];
for (const item of $input.all()) {
  const prs = item.json.values || [];
  for (const pr of prs) {
    const repoSlug = pr.destination?.repository?.full_name || '';
    if (!repoSlug) continue;
    prItems.push({ json: { pr, repoSlug, since: item.json.since || new Date(Date.now() - 150000).toISOString() } });
  }
}
return prItems.length ? prItems : [{ json: { _skip: true } }];

// Wrap the activity response so it doesn't overwrite PR data on merge.
return $input.all().map(item => ({
  json: { _activity: item.json.values || [] }
}));

// Classify PR changes using the activity feed.
// Produces granular raw_event_type and contextual body.

const POLL_WINDOW_MS = 150000; // 2.5 minutes
const now = Date.now();

const pr = $json.pr;
const repoSlug = $json.repoSlug;
const activity = $json._activity || []; // activity feed entries from Wrap Activity node
const state = (pr.state || '').toUpperCase();
const isNew = pr.created_on === pr.updated_on;

// --- Find recent activity within our poll window ---
const recentActivity = activity.filter(a => {
  // Activity entries have different shapes; find the timestamp
  const ts = a.update?.date || a.comment?.created_on || a.approval?.date || a.pull_request?.updated_on || '';
  if (!ts) return false;
  return (now - new Date(ts).getTime()) < POLL_WINDOW_MS;
});

// --- Classify the change ---
let rawEventType = 'pr_updated';
let body = '';
let changeType = 'generic_update';
let previousState = null;
let newState = null;
let actorName = pr.author?.display_name || 'Unknown';
let actorHandle = pr.author?.nickname || pr.author?.uuid || '';
let commentId = null;

if (isNew) {
  // Brand-new PR
  rawEventType = 'pr_created';
  changeType = 'created';
  body = pr.description || pr.title || '';

} else {
  // Check activity feed for specific change types (newest first)
  let classified = false;

  for (const entry of recentActivity) {
    if (entry.update && !classified) {
      // State/field update
      const update = entry.update;
      const fromState = (update.state?.previous || '').toUpperCase();
      const toState = (update.state?.new || state).toUpperCase();

      if (update.author) {
        actorName = update.author.display_name || actorName;
        actorHandle = update.author.nickname || update.author.uuid || actorHandle;
      }

      if (toState === 'MERGED' && fromState !== 'MERGED') {
        rawEventType = 'pr_merged';
        changeType = 'merged';
        body = `Pull request merged into ${pr.destination?.branch?.name || 'target branch'}.`;
        if (pr.merge_commit?.hash) body += ` Merge commit: ${pr.merge_commit.hash.substring(0, 8)}.`;
        previousState = fromState;
        newState = 'MERGED';
        classified = true;
      } else if (toState === 'DECLINED' && fromState !== 'DECLINED') {
        rawEventType = 'pr_declined';
        changeType = 'declined';
        body = `Pull request declined.`;
        if (update.reason) body += ` Reason: ${update.reason}`;
        previousState = fromState;
        newState = 'DECLINED';
        classified = true;
      } else if (fromState === 'MERGED' || fromState === 'DECLINED') {
        rawEventType = 'pr_reopened';
        changeType = 'reopened';
        body = `Pull request reopened: ${fromState} → ${toState}.`;
        previousState = fromState;
        newState = toState;
        classified = true;
      } else if (update.title || update.description || update.destination) {
        rawEventType = 'pr_updated';
        changeType = 'fields_updated';
        const changes = [];
        if (update.title) changes.push('title');
        if (update.description) changes.push('description');
        if (update.destination) changes.push('target branch');
        if (update.reviewers) changes.push('reviewers');
        body = `PR fields updated: ${changes.join(', ')}.`;
        classified = true;
      }
    }

    if (entry.approval && !classified) {
      const approval = entry.approval;
      rawEventType = 'pr_approved';
      changeType = 'approved';
      actorName = approval.user?.display_name || actorName;
      actorHandle = approval.user?.nickname || approval.user?.uuid || actorHandle;
      body = `Pull request approved by ${actorName}.`;
      classified = true;
    }

    if (entry.comment && !classified) {
      const comment = entry.comment;
      rawEventType = 'pr_commented';
      changeType = 'commented';
      actorName = comment.user?.display_name || actorName;
      actorHandle = comment.user?.nickname || comment.user?.uuid || actorHandle;
      const commentBody = comment.content?.raw || comment.content?.markup || '';
      body = `New comment from ${actorName}:\n${commentBody}`;
      // Capture comment ID so replies can target this thread
      if (comment.id) commentId = String(comment.id);
      // Check if it's an inline code comment
      if (comment.inline) {
        const file = comment.inline.path || 'unknown file';
        const line = comment.inline.to || comment.inline.from || '';
        body = `Inline comment on ${file}${line ? ':' + line : ''} from ${actorName}:\n${commentBody}`;
        changeType = 'inline_comment';
      }
      classified = true;
    }

    if (classified) break;
  }

  // Fallback: no recent activity matched — use PR state
  if (!classified) {
    if (state === 'MERGED') {
      rawEventType = 'pr_merged';
      changeType = 'merged';
      body = `Pull request merged into ${pr.destination?.branch?.name || 'target branch'}.`;
    } else if (state === 'DECLINED') {
      rawEventType = 'pr_declined';
      changeType = 'declined';
      body = `Pull request declined.`;
    } else {
      rawEventType = 'pr_updated';
      changeType = 'no_change_detected';
      body = `PR polled with no detectable changes. Current state: ${state}.`;
    }
  }
}

const epoch = new Date(pr.updated_on || Date.now()).getTime();

return {
  json: {
    event_id: 'evt_bb_pr_' + repoSlug.replace('/', '_') + '_' + pr.id + '_' + epoch,
    timestamp: pr.updated_on || new Date().toISOString(),
    source: {
      platform: 'bitbucket',
      connection_id: $workflow.id,
      raw_event_type: rawEventType
    },
    actor: {
      name: actorName,
      email: '',
      platform_handle: actorHandle
    },
    subject: {
      type: 'pull_request',
      id: 'PR-' + pr.id,
      title: pr.title || '',
      url: (pr.links && pr.links.html && pr.links.html.href) || ''
    },
    content: {
      body: body,
      attachments: [],
      metadata: {
        bb_repository: repoSlug,
        bb_branch: pr.source?.branch?.name || '',
        bb_target_branch: pr.destination?.branch?.name || '',
        bb_state: state,
        bb_reviewers: (pr.reviewers || []).map(r => r.display_name || r.nickname || ''),
        bb_change_type: changeType,
        bb_previous_state: previousState,
        bb_new_state: newState,
        bb_description: pr.description || '',
        bb_comment_id: commentId,
        participants: [
          { role: 'author', name: pr.author?.display_name || '', handle: pr.author?.nickname || pr.author?.uuid || '' },
          ...(pr.reviewers || []).map(r => ({ role: 'reviewer', name: r.display_name || '', handle: r.nickname || r.uuid || '' }))
        ]
      }
    }
  }
};
